function moveGenerateBox() {
    const generateBox = document.getElementById('txt2img_generate_box');
    const actionsColumn = document.getElementById('txt2img_actions_column');

    if (!generateBox || !actionsColumn) {
        console.log('Elements not found, retrying in 1s...');
        setTimeout(moveGenerateBox, 1000);
        return;
    }

    // 移动节点，这不会影响已绑定的事件监听器
    actionsColumn.appendChild(generateBox);
    console.log('Generate box moved successfully');
}


function initWebUI() {
    // 尝试在主文档中查找元素
    let div = document.getElementById('component-51');
    if (!div) {
        console.log('未找到元素,5秒后重试');
        setTimeout(checkAndModifyDiv, 5000);
        return;
    }

    div.style.gridTemplateColumns = '1fr 0px';

    // 同样在相应文档中查找txt2img_results
    let txt2img_results;
    if (div.ownerDocument === document) {
        txt2img_results = document.getElementById('txt2img_results');
    } else {
        txt2img_results = div.ownerDocument.getElementById('txt2img_results');
    }

    if (txt2img_results) {
        txt2img_results.style.display = 'none';
    }

    setTimeout(moveGenerateBox, 1000);
}


function observeGallery() {
    const gallery = document.getElementById('txt2img_gallery');
    if (!gallery) {
        console.log('Gallery not found, retrying...');
        setTimeout(observeGallery, 1000);
        return;
    }

    // 创建观察器配置
    const config = {
        childList: true, // 监听子节点变化
        subtree: true,   // 监听所有后代节点变化
    };
    let lastLink = null
    // 创建观察器实例
    const observer = new MutationObserver((mutations) => {
        mutations.forEach((mutation) => {
            // 检查新增的节点
            mutation.addedNodes.forEach((node) => {
                // 如果新增的是img标签
                // console.log(node);
                if (node.nodeName === 'IMG') {
                    // console.log('New image src:', node.src);
                    if (!node.src.startsWith('data:image/png;base64') && node.src !== lastLink) {
                        sendMessageToBackground({
                            type: 'new_image',
                            src: node.src
                        });
                        lastLink = node.src
                    }
                }

            });
        });
    });

    // 开始观察
    observer.observe(gallery, config);
    console.log('Started observing gallery');
}


function sendMessageToBackground(message) {
    chrome.runtime.sendMessage(message);
}


// 如果当前窗口不是顶层窗口，也就是插件内部，则5秒后检查并修改元素
console.log('content-script.js loaded');
if (window !== window.top) {
    console.log('当前窗口是插件内部，5秒后检查并修改元素');
    setTimeout(initWebUI, 5000);
    // 启动观察
    observeGallery();
} 